### Error Handling Philosophy

The caut integration must be **non-blocking** and **graceful**:

```go
// Example usage in agent health check
func (h *HealthChecker) GetProviderUsage(agentType string) *caut.ProviderPayload {
    if !h.cautClient.IsAvailable() {
        // caut not installed - continue without provider data
        log.Debug("caut not available, skipping provider usage")
        return nil
    }

    provider := caut.AgentTypeToProvider(agentType)
    if provider == "" {
        return nil
    }

    ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
    defer cancel()

    payload, err := h.cautClient.GetProviderUsage(ctx, provider)
    if err != nil {
        // caut failed - log and continue
        log.Warn("caut query failed", "error", err)
        return nil
    }

    return payload
}
```

### Caching Strategy

To avoid hammering caut (which may make API calls), we cache results:

```go
type CachedClient struct {
    client    *Client
    cache     map[string]*cachedResult
    cacheTTL  time.Duration
    mu        sync.RWMutex
}

type cachedResult struct {
    payload   *ProviderPayload
    fetchedAt time.Time
}

func (c *CachedClient) GetProviderUsage(ctx context.Context, provider string) (*ProviderPayload, error) {
    c.mu.RLock()
    if cached, ok := c.cache[provider]; ok {
        if time.Since(cached.fetchedAt) < c.cacheTTL {
            c.mu.RUnlock()
            return cached.payload, nil
        }
    }
    c.mu.RUnlock()

    // Cache miss or expired - fetch fresh
    payload, err := c.client.GetProviderUsage(ctx, provider)
    if err != nil {
        return nil, err
    }

    c.mu.Lock()
    c.cache[provider] = &cachedResult{
        payload:   payload,
        fetchedAt: time.Now(),
    }
    c.mu.Unlock()

    return payload, nil
}
```

